// BTButton types — Figma source: node 114:2645.

/// Visual style of the button.
enum BTButtonVariant {
  primary,
  secondary,
  destructive,
  outline,
  ghost,
}

/// Padding scale.
enum BTButtonSize {
  /// Default — 12 px vertical × 16 px horizontal.
  md,

  /// Small — 8 px on all sides.
  sm,
}

/// BTButton — interactive action atom.
/// Figma source: node 114:2645.
///
/// Width is intrinsic — the button never expands to fill its parent.
/// Wrap in [Expanded] or set an explicit width when full-width is needed.
///
/// Hover and pressed states are animated via [AnimationController].
/// Pass [onPressed] as `null` to disable.
///
/// ## Usage:
/// ```dart
/// // Primary (default)
/// BTButton(label: 'Save', onPressed: handleSave)
///
/// // With left icon
/// BTButton(
///   label: 'Upload',
///   variant: BTButtonVariant.secondary,
///   leftIcon: const Icon(Icons.upload, size: 16),
///   onPressed: handleUpload,
/// )
///
/// // Icon only
/// BTButton.iconOnly(
///   icon: const Icon(Icons.close, size: 16),
///   variant: BTButtonVariant.ghost,
///   onPressed: handleClose,
/// )
///
/// // Disabled (onPressed = null)
/// BTButton(label: 'Submit', onPressed: null)
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/atoms/button/button.types.dart';
import 'package:btech_ui/src/components/atoms/button/internal/button.colors.dart';
import 'package:btech_ui/src/components/atoms/button/internal/inner_shadow_container.dart';
import 'package:flutter/material.dart';

/// Action button atom. See file header for usage examples.
class BTButton extends StatefulWidget {
  /// Standard button with an optional text [label] and optional icons.
  const BTButton({
    required this.onPressed,
    this.label,
    this.variant = BTButtonVariant.primary,
    this.size = BTButtonSize.md,
    this.leftIcon,
    this.rightIcon,
    super.key,
  })  : _iconOnly = false,
        _icon = null;

  /// Square button that shows a single [icon] — no label.
  const BTButton.iconOnly({
    required Widget icon,
    required this.onPressed,
    this.variant = BTButtonVariant.primary,
    this.size = BTButtonSize.md,
    super.key,
  })  : _iconOnly = true,
        _icon = icon,
        label = null,
        leftIcon = null,
        rightIcon = null;

  /// Text shown inside the button (ignored in icon-only mode).
  final String? label;

  /// Visual style.
  final BTButtonVariant variant;

  /// Padding scale. [BTButtonSize.md] = 12×16 px, [BTButtonSize.sm] = 8 px.
  final BTButtonSize size;

  /// Callback invoked on tap. `null` disables the button.
  final VoidCallback? onPressed;

  /// Widget rendered to the left of [label] (16×16 recommended).
  final Widget? leftIcon;

  /// Widget rendered to the right of [label] (16×16 recommended).
  final Widget? rightIcon;

  final bool _iconOnly;
  final Widget? _icon;

  @override
  State<BTButton> createState() => _BTButtonState();
}

class _BTButtonState extends State<BTButton>
    with SingleTickerProviderStateMixin {
  // ── Animation ──────────────────────────────────────────────────────────────
  // 120 ms forward (easeOut) / 200 ms reverse (easeIn) mirrors buma-ui timing.

  late final AnimationController _animationController;
  late final Animation<double> _pressAnim;
  bool _isPressed = false;
  final bool _hovered = false;

  @override
  void initState() {
    super.initState();
    _animationController = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 120),
      reverseDuration: const Duration(milliseconds: 180),
      value: 0,
    );
    _pressAnim = CurvedAnimation(
      parent: _animationController,
      curve: Curves.linear,
      reverseCurve: Curves.easeInCubic,
    );
  }

  @override
  void dispose() {
    _animationController.dispose();
    super.dispose();
  }

  bool get _disabled => widget.onPressed == null;

  /// Handles when user starts pressing the button
  void _onTapDown(TapDownDetails details) {
    if (widget.onPressed != null && !_isPressed) {
      setState(() {
        _isPressed = true;
      });
      _animationController.forward();
    }
  }

  /// Handles when user releases the button (successful tap)
  void _onTapUp(TapUpDetails details) {
    if (widget.onPressed != null && _isPressed) {
      setState(() {
        _isPressed = false;
      });
      _animationController.reverse();
    }
  }

  /// Handles when the tap gesture is canceled
  void _onTapCancel() {
    if (widget.onPressed != null && _isPressed) {
      setState(() {
        _isPressed = false;
      });
      _animationController.reverse();
    }
  }

  /// Handles the actual tap callback
  void _onTap() {
    if (widget.onPressed != null) {
      widget.onPressed?.call();
    }
  }



  @override
  Widget build(BuildContext context) {
    final colors = context.btechColor;
    final radius = context.btechRadius.sm;
    final isSmall = widget.size == BTButtonSize.sm;
    final isIconOnly = widget._iconOnly;

    // Resolve the two colour anchors — idle (or hover) and fully pressed.
    // AnimatedBuilder lerps between them on every frame.
    final idleState = BTButtonStateExt.of(
      disabled: _disabled,
      hovered: _hovered,
      pressed: false,
    );
    final pressedState = BTButtonStateExt.of(
      disabled: false,
      hovered: true,
      pressed: true,
    );
    final idleCol = buttonColors(
      variant: widget.variant,
      state: idleState,
      colors: colors,
    );
    final pressedCol = buttonColors(
      variant: widget.variant,
      state: pressedState,
      colors: colors,
    );

    final padding = isIconOnly
        ? EdgeInsets.all(isSmall ? 8 : 12)
        : EdgeInsets.symmetric(
            vertical: isSmall ? 8 : 12,
            horizontal: isSmall ? 8 : 16,
          );
    final gap = isSmall ? 2.0 : 4.0;

    return MouseRegion(
      cursor:
          _disabled ? SystemMouseCursors.forbidden : SystemMouseCursors.click,
      child: GestureDetector(
        onTap: _disabled ? null : _onTap,
        onTapDown: _disabled ? null : _onTapDown,
        onTapUp: _disabled ? null : _onTapUp,
        onTapCancel: _disabled ? null : _onTapCancel,
        // IntrinsicWidth: button only as wide as its content.
        // Consumers wrap in Expanded/SizedBox when full-width is needed.
        child: IntrinsicWidth(
          child: AnimatedBuilder(
            animation: _pressAnim,
            builder: (context, _) {
              final t = _pressAnim.value;

              // Smoothly lerp background, foreground and border colours.
              final bg = Color.lerp(idleCol.bg, pressedCol.bg, t) ?? idleCol.bg;
              final fg = Color.lerp(idleCol.fg, pressedCol.fg, t) ?? idleCol.fg;

              final idleBorder = idleCol.border ?? Colors.transparent;
              final pressBorder = pressedCol.border ?? Colors.transparent;
              final borderColor =
                  Color.lerp(idleBorder, pressBorder, t) ?? idleBorder;
              final border =
                  (idleCol.border != null || pressedCol.border != null)
                      ? Border.all(color: borderColor)
                      : null;

              // Shadow fades from transparent → rgba(0,0,0,0.25).
              final showShadow = t > 0.01 && !_disabled;

              // Build content with current foreground colour.
              Widget content;
              if (isIconOnly) {
                content = IconTheme(
                  data: IconThemeData(size: 16, color: fg),
                  child: widget._icon!,
                );
              } else {
                content = Row(
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    if (widget.leftIcon != null) ...[
                      IconTheme(
                        data: IconThemeData(size: 16, color: fg),
                        child: widget.leftIcon!,
                      ),
                      SizedBox(width: gap),
                    ],
                    if (widget.label != null)
                      Text(
                        widget.label!,
                        style: TextStyle(
                          color: fg,
                          fontSize: 12,
                          fontWeight: FontWeight.w500,
                          fontFamily: BTechTypography.fontFamily,
                          height: 16 / 12,
                          letterSpacing: 0,
                        ),
                      ),
                    if (widget.rightIcon != null) ...[
                      SizedBox(width: gap),
                      IconTheme(
                        data: IconThemeData(size: 16, color: fg),
                        child: widget.rightIcon!,
                      ),
                    ],
                  ],
                );
              }

              return BTInnerShadowContainer(
                borderRadius: radius,
                backgroundColor: bg,
                border: border,
                isShadowTopLeft: showShadow,
                isShadowTopRight: showShadow,
                shadowColor: BTechShadow.button.pressed.first.color,
                blur: BTechShadow.button.pressed.first.blurRadius,
                offset: BTechShadow.button.pressed.first.offset,
                alignment: Alignment.center,
                animationCurve: Curves.linear,
                animationDuration: const Duration(milliseconds: 200),
                child: Padding(
                  padding: padding,
                  child: content,
                ),
              );
            },
          ),
        ),
      ),
    );
  }
}

// Button color logic — Figma node 114:2645.
// All colors resolved from btech semantic tokens via BuildContext.
// Do NOT hardcode Color(0xFF...) here.

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/atoms/button/button.types.dart';
import 'package:flutter/material.dart';

/// Resolves background, foreground and border colors for the given
/// [variant] and interaction [state].
({Color bg, Color fg, Color? border}) buttonColors({
  required BTButtonVariant variant,
  required BTButtonState state,
  required BTechColorTheme colors,
}) {
  return switch ((variant, state)) {
    // ── Primary ──────────────────────────────────────────────────────────────
    (BTButtonVariant.primary, BTButtonState.disabled) => (
        bg: colors.bg.subtlest,
        fg: colors.text.inverse,
        border: null,
      ),
    (BTButtonVariant.primary, BTButtonState.hoverOrPressed) => (
        bg: colors.brand.primaryBold,
        fg: colors.text.inverse,
        border: null,
      ),
    (BTButtonVariant.primary, _) => (
        bg: colors.brand.primary,
        fg: colors.text.inverse,
        border: null,
      ),

    // ── Secondary ────────────────────────────────────────────────────────────
    (BTButtonVariant.secondary, BTButtonState.disabled) => (
        bg: colors.bg.subtle,
        fg: colors.bg.subtlest,
        border: null,
      ),
    (BTButtonVariant.secondary, BTButtonState.hoverOrPressed) => (
        bg: colors.bg.subtler,
        fg: colors.text.primary,
        border: null,
      ),
    (BTButtonVariant.secondary, _) => (
        bg: colors.bg.secondary,
        fg: colors.text.primary,
        border: null,
      ),

    // ── Destructive ──────────────────────────────────────────────────────────
    (BTButtonVariant.destructive, BTButtonState.disabled) => (
        bg: colors.bg.subtlest,
        fg: colors.text.inverse,
        border: null,
      ),
    (BTButtonVariant.destructive, BTButtonState.hoverOrPressed) => (
        bg: colors.ext.errorBold,
        fg: colors.text.inverse,
        border: null,
      ),
    (BTButtonVariant.destructive, _) => (
        bg: colors.ext.error,
        fg: colors.text.inverse,
        border: null,
      ),

    // ── Outline ──────────────────────────────────────────────────────────────
    (BTButtonVariant.outline, BTButtonState.disabled) => (
        bg: Colors.transparent,
        fg: colors.bg.subtlest,
        border: colors.bg.subtlest,
      ),
    (BTButtonVariant.outline, BTButtonState.hoverOrPressed) => (
        bg: colors.bg.subtler,
        fg: colors.text.primary,
        border: colors.border.primary,
      ),
    (BTButtonVariant.outline, _) => (
        bg: Colors.transparent,
        fg: colors.text.primary,
        border: colors.border.primary,
      ),

    // ── Ghost ────────────────────────────────────────────────────────────────
    (BTButtonVariant.ghost, BTButtonState.disabled) => (
        bg: Colors.transparent,
        fg: colors.bg.subtlest,
        border: null,
      ),
    (BTButtonVariant.ghost, BTButtonState.hoverOrPressed) => (
        bg: colors.bg.subtler,
        fg: colors.text.primary,
        border: null,
      ),
    (BTButtonVariant.ghost, _) => (
        bg: Colors.transparent,
        fg: colors.text.primary,
        border: null,
      ),
  };
}

/// Interaction state used for color resolution.
enum BTButtonState { idle, hoverOrPressed, disabled }

extension BTButtonStateExt on BTButtonState {
  static BTButtonState of({
    required bool disabled,
    required bool hovered,
    required bool pressed,
  }) {
    if (disabled) return BTButtonState.disabled;
    if (hovered || pressed) return BTButtonState.hoverOrPressed;
    return BTButtonState.idle;
  }
}

// BTech UI — InnerShadowContainer
// A Stack-based widget that draws an inner shadow via CustomPaint.
//
// Flutter's built-in BoxShadow(blurStyle: BlurStyle.inner) does not animate
// cleanly and cannot lerp with BoxDecoration.  This widget uses the same
// clip-and-translate CustomPainter technique as buma_design_system's
// InnerShadowContainer so the button pressed state is visually identical.
//
// Animation is CALLER-DRIVEN: this widget is intentionally stateless and
// contains no AnimationController.  The caller (e.g. BTButton's
// AnimatedBuilder) lerps backgroundColor and shadowColor each frame and
// rebuilds this widget with the interpolated values.  The painter
// short-circuits immediately when shadowColor.alpha == 0, so there is
// zero overdraw at rest.
//
// [animationDuration] and [animationCurve] are accepted for API
// compatibility but are intentionally ignored — they were used by the old
// AnimatedContainer/AnimatedOpacity approach which caused double-rebuild
// flicker.
//
// Usage:
// ```dart
// BTInnerShadowContainer(
//   borderRadius: context.btechRadius.sm,
//   backgroundColor: bg,          // already lerped by caller
//   isShadowTopLeft: showShadow,
//   isShadowTopRight: showShadow,
//   shadowColor: shadowColor,      // alpha encodes opacity — 0x00 = no draw
//   blur: 4,
//   offset: const Offset(0, 4),
//   animationDuration: Duration.zero,
//   child: content,
// )
// ```

import 'package:flutter/material.dart';

/// A stateless container that renders an inner (inset) shadow via
/// [CustomPaint].
///
/// All animation is caller-driven — the caller lerps [backgroundColor] and
/// [shadowColor] each frame.  When [shadowColor] has `alpha == 0` the painter
/// exits immediately (no overdraw).  [animationDuration] and [animationCurve]
/// are accepted but ignored.
///
/// Toggle [isShadowTopLeft] / [isShadowTopRight] / [isShadowBottomLeft] /
/// [isShadowBottomRight] to enable the shadow from the corresponding edge.
class BTInnerShadowContainer extends StatelessWidget {
  /// Creates a [BTInnerShadowContainer].
  const BTInnerShadowContainer({
    super.key,
    this.height,
    this.width,
    this.border,
    this.borderRadius = 8.0,
    this.backgroundColor = Colors.white,
    this.isShadowTopLeft = false,
    this.isShadowTopRight = false,
    this.isShadowBottomRight = false,
    this.isShadowBottomLeft = false,
    this.blur = 4.0,
    this.offset = const Offset(0, 4),
    this.shadowColor = Colors.black26,
    this.child,
    this.alignment = Alignment.center,
    this.animationDuration = const Duration(milliseconds: 200),
    this.animationCurve = Curves.linear,
  });

  /// The height of the container.
  final double? height;

  /// The width of the container.
  final double? width;

  /// Optional border drawn beneath the shadow layer.
  final BoxBorder? border;

  /// Corner radius in logical pixels.
  final double borderRadius;

  /// Background fill colour.
  final Color backgroundColor;

  /// Show inner shadow from the top-left corner.
  final bool isShadowTopLeft;

  /// Show inner shadow from the top-right corner.
  final bool isShadowTopRight;

  /// Show inner shadow from the bottom-right corner.
  final bool isShadowBottomRight;

  /// Show inner shadow from the bottom-left corner.
  final bool isShadowBottomLeft;

  /// Gaussian blur radius (matches CSS blur value 1:1).
  final double blur;

  /// Offset of the shadow relative to the container edge.
  final Offset offset;

  /// Colour of the shadow.
  final Color shadowColor;

  /// Widget rendered inside the container.
  final Widget? child;

  /// How the child is aligned inside the container.
  final AlignmentGeometry alignment;

  /// Duration for background colour + shadow visibility transitions.
  final Duration animationDuration;

  /// Animation curve for the transitions.
  final Curve animationCurve;

  @override
  Widget build(BuildContext context) {
    final hasShadow = isShadowTopLeft ||
        isShadowTopRight ||
        isShadowBottomRight ||
        isShadowBottomLeft;
    return Stack(
      children: [
        // Plain Container — animation is driven externally by the caller.
        AnimatedContainer(
          duration: animationDuration,
          curve: animationCurve,
          height: height,
          width: width,
          alignment: alignment,
          decoration: BoxDecoration(
            color: backgroundColor,
            borderRadius: BorderRadius.circular(borderRadius),
            border: border,
          ),
          child: child,
        ),
        Positioned.fill(
          child: AnimatedOpacity(
            duration: animationDuration,
            curve: animationCurve,
            opacity: hasShadow ? 1.0 : 0.0,
            child: ClipRRect(
              borderRadius: BorderRadius.circular(borderRadius),
              child: CustomPaint(
                painter: _BTInnerShadowPainter(
                  shadowColor: shadowColor,
                  blur: blur,
                  offset: offset,
                  borderRadius: borderRadius,
                  isShadowTopLeft: isShadowTopLeft,
                  isShadowTopRight: isShadowTopRight,
                  isShadowBottomRight: isShadowBottomRight,
                  isShadowBottomLeft: isShadowBottomLeft,
                ),
              ),
            ),
          ),
        ),
      ],
    );
  }
}

// ── Painter ───────────────────────────────────────────────────────────────

class _BTInnerShadowPainter extends CustomPainter {
  const _BTInnerShadowPainter({
    required this.shadowColor,
    required this.blur,
    required this.offset,
    required this.borderRadius,
    this.isShadowTopLeft = false,
    this.isShadowTopRight = false,
    this.isShadowBottomRight = false,
    this.isShadowBottomLeft = false,
  });

  final Color shadowColor;
  final double blur;
  final Offset offset;
  final double borderRadius;
  final bool isShadowTopLeft;
  final bool isShadowTopRight;
  final bool isShadowBottomRight;
  final bool isShadowBottomLeft;

  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = shadowColor
      ..maskFilter = MaskFilter.blur(BlurStyle.normal, blur);

    final rect = Offset.zero & size;
    final rrect = RRect.fromRectAndRadius(rect, Radius.circular(borderRadius));

    final outer = Path()
      ..addRect(
        Rect.fromLTRB(
          -size.width,
          -size.height,
          size.width * 2,
          size.height * 2,
        ),
      );

    final inner = Path()
      ..addRRect(rrect)
      ..fillType = PathFillType.evenOdd;

    canvas.saveLayer(rect, Paint());

    void drawShadow(double dx, double dy) {
      canvas
        ..save()
        ..translate(dx, dy)
        ..drawPath(
          Path.combine(PathOperation.difference, outer, inner),
          paint,
        )
        ..restore();
    }

    if (isShadowBottomRight) drawShadow(-offset.dx.abs(), -offset.dy.abs());
    if (isShadowBottomLeft) drawShadow(offset.dx.abs(), -offset.dy.abs());
    if (isShadowTopLeft) drawShadow(offset.dx.abs(), offset.dy.abs());
    if (isShadowTopRight) drawShadow(-offset.dx.abs(), offset.dy.abs());

    canvas.restore();
  }

  @override
  bool shouldRepaint(covariant CustomPainter oldDelegate) => true;
}
